content.content:
   1→/* ── Mobile top header ── Hidden on desktop ── */
   2→.mobile-top-header{
   3→    display: none;
   4→}
   5→.mobile-write-btn{
   6→    display: none;
   7→}
   8→
   9→.newsfeed-header{
  10→}
  11→.search-shell{
  12→    position: sticky;
  13→    top: 0;
  14→    z-index: 14;
  15→    align-self: stretch;
  16→    width: 100%;
  17→    max-width: 100%;
  18→}
  19→.search-top-bar{
  20→    position: relative;
  21→    z-index: 12;
  22→    display: flex;
  23→    align-items: center;
  24→    gap: 0.5rem;
  25→    width: 100%;
  26→    padding: 0.65rem 0.75rem 0.75rem 0.75rem;
  27→    box-sizing: border-box;
  28→    background: var(--bg-primary);
  29→    border-bottom: 1px solid var(--border-card);
  30→}
  31→.search-input-wrap{
  32→    position: relative;
  33→    display: flex;
  34→    align-items: center;
  35→    flex: 1;
  36→}
  37→.search-icon{
  38→    position: absolute;
  39→    left: 0.85rem;
  40→    width: 15px;
  41→    height: 15px;
  42→    color: var(--text-faint);
  43→    pointer-events: none;
  44→    transition: color 0.25s ease, transform 0.25s ease;
  45→}
  46→.search-input-wrap:focus-within .search-icon{
  47→    color: #D4A853;
  48→    transform: scale(1.08);
  49→}
  50→.search-input{
  51→    width: 100%;
  52→    border: 1.5px solid var(--border-card);
  53→    border-radius: 10px;
  54→    padding: 0.6rem 0.9rem 0.6rem 2.4rem;
  55→    font-family: var(--font-ui);
  56→    font-size: 0.84rem;
  57→    font-weight: 450;
  58→    letter-spacing: 0.01rem;
  59→    color: var(--text-heading);
  60→    background: var(--bg-secondary);
  61→    outline: none;
  62→    transition: border-color 0.3s ease, box-shadow 0.3s ease, background 0.3s ease;
  63→}
  64→.search-input::placeholder{
  65→    color: var(--text-faint);
  66→    font-weight: 400;
  67→    letter-spacing: 0.015rem;
  68→}
  69→.search-input:focus{
  70→    border-color: #D4A853;
  71→    background: var(--bg-card);
  72→    box-shadow:
  73→        0 0 0 3px rgba(212, 168, 83, 0.1),
  74→        0 2px 8px rgba(212, 168, 83, 0.06);
  75→}
  76→.search-clear-btn{
  77→    border: 1.5px solid var(--border-card);
  78→    background: var(--bg-secondary);
  79→    color: var(--text-secondary);
  80→    border-radius: 8px;
  81→    font-family: var(--font-ui);
  82→    font-size: 0.7rem;
  83→    font-weight: 600;
  84→    letter-spacing: 0.02rem;
  85→    padding: 0.4rem 0.72rem;
  86→    cursor: pointer;
  87→    transition: background 0.2s ease, border-color 0.2s ease, color 0.2s ease;
  88→    white-space: nowrap;
  89→}
  90→.search-clear-btn:hover{
  91→    background: var(--bg-hover);
  92→    border-color: #D4A853;
  93→    color: #D4A853;
  94→}
  95→/* ── Nav row (Freedom Wall + Stories) ── */
  96→.search-nav-row{
  97→    display: flex;
  98→    gap: 6px;
  99→    padding: 0.4rem 0.75rem;
 100→}
 101→.search-nav-btn{
 102→    display: flex;
 103→    align-items: center;
 104→    justify-content: center;
 105→    gap: 0.35rem;
 106→    flex: 1;
 107→    border-radius: 999px;
 108→    font-family: var(--font-ui);
 109→    font-size: 0.74rem;
 110→    font-weight: 700;
 111→    letter-spacing: 0.01rem;
 112→    padding: 0.48rem 0.7rem;
 113→    cursor: pointer;
 114→    white-space: nowrap;
 115→    transition: background 0.15s ease, transform 0.15s ease, box-shadow 0.15s ease;
 116→}
 117→.search-nav-btn:active{
 118→    transform: scale(0.97);
 119→}
 120→.search-nav-fw{
 121→    border: 1.5px solid rgba(234, 179, 56, 0.35);
 122→    background: linear-gradient(135deg, rgba(234, 179, 56, 0.12), rgba(255, 204, 51, 0.08));
 123→    color: #e6a817;
 124→}
 125→.search-nav-fw:hover{
 126→    background: linear-gradient(135deg, rgba(234, 179, 56, 0.22), rgba(255, 204, 51, 0.16));
 127→    box-shadow: 0 0 10px rgba(234, 179, 56, 0.15);
 128→}
 129→.search-nav-stories{
 130→    border: 1.5px solid rgba(234, 179, 56, 0.35);
 131→    background: linear-gradient(135deg, rgba(234, 179, 56, 0.12), rgba(255, 204, 51, 0.08));
 132→    color: #e6a817;
 133→}
 134→.search-nav-stories:hover{
 135→    background: linear-gradient(135deg, rgba(234, 179, 56, 0.22), rgba(255, 204, 51, 0.16));
 136→    box-shadow: 0 0 10px rgba(234, 179, 56, 0.15);
 137→}
 138→.search-mode-pill{
 139→    display: flex;
 140→    align-items: center;
 141→    border-radius: 8px;
 142→    border: 1.5px solid var(--border-card);
 143→    background: var(--bg-secondary);
 144→    color: var(--text-faint);
 145→    font-family: var(--font-ui);
 146→    font-size: 0.65rem;
 147→    font-weight: 650;
 148→    letter-spacing: 0.04rem;
 149→    text-transform: uppercase;
 150→    padding: 0.35rem 0.6rem;
 151→    white-space: nowrap;
 152→}
 153→.search-gallery-hint{
 154→    margin: 0 0.75rem 0.45rem 0.75rem;
 155→    width: fit-content;
 156→    border: 1.5px solid var(--border-card);
 157→    background: var(--bg-secondary);
 158→    color: var(--accent-sage);
 159→    border-radius: 8px;
 160→    font-family: var(--font-ui);
 161→    font-size: 0.68rem;
 162→    font-weight: 600;
 163→    letter-spacing: 0.01rem;
 164→    padding: 0.34rem 0.62rem;
 165→    cursor: pointer;
 166→    transition: background 0.2s ease, border-color 0.2s ease;
 167→}
 168→.search-gallery-hint:hover{
 169→    background: var(--bg-hover);
 170→    border-color: var(--accent-sage);
 171→}
 172→.search-empty-state{
 173→    display: flex;
 174→    justify-content: center;
 175→    align-items: center;
 176→    width: 100%;
 177→    padding: 2rem 0.5rem;
 178→    font-family: var(--font-ui);
 179→    font-size: 0.84rem;
 180→    font-weight: 500;
 181→    color: var(--text-faint);
 182→    letter-spacing: 0.01rem;
 183→}
 184→.search-empty-state.is-canvas-only{
 185→    flex-wrap: wrap;
 186→    gap: 0.28rem;
 187→}
 188→.search-empty-link{
 189→    border: none;
 190→    background: transparent;
 191→    color: var(--accent-sage);
 192→    font-family: var(--font-ui);
 193→    font-size: 0.84rem;
 194→    font-weight: 650;
 195→    cursor: pointer;
 196→    text-decoration: underline;
 197→}
 198→.search-empty-link:hover{
 199→    opacity: 0.88;
 200→}
 201→.search-suggestions-dropdown{
 202→    position: absolute;
 203→    left: 0.75rem;
 204→    right: 0.75rem;
 205→    top: calc(100% - 0.15rem);
 206→    z-index: 30;
 207→    border: 1.5px solid var(--border-card);
 208→    border-radius: 10px;
 209→    background: var(--bg-elevated);
 210→    box-shadow:
 211→        0 8px 24px rgba(0, 0, 0, 0.1),
 212→        0 2px 8px rgba(0, 0, 0, 0.06);
 213→    max-height: 320px;
 214→    overflow-y: auto;
 215→    padding: 0.3rem 0;
 216→    animation: searchDropdownIn 0.2s ease-out;
 217→}
 218→@keyframes searchDropdownIn{
 219→    from{
 220→        opacity: 0;
 221→        transform: translateY(-6px);
 222→    }
 223→    to{
 224→        opacity: 1;
 225→        transform: translateY(0);
 226→    }
 227→}
 228→.search-suggestion-item{
 229→    width: 100%;
 230→    text-align: left;
 231→    border: none;
 232→    background: transparent;
 233→    cursor: pointer;
 234→    display: flex;
 235→    flex-direction: column;
 236→    gap: 0.15rem;
 237→    padding: 0.6rem 0.85rem;
 238→    transition: background 0.15s ease;
 239→    border-left: 2.5px solid transparent;
 240→}
 241→.search-suggestion-item:hover{
 242→    background: var(--bg-pill);
 243→    border-left-color: #D4A853;
 244→}
 245→.search-suggestion-title{
 246→    font-family: var(--font-ui);
 247→    font-size: 0.8rem;
 248→    font-weight: 600;
 249→    color: var(--text-heading);
 250→    white-space: nowrap;
 251→    overflow: hidden;
 252→    text-overflow: ellipsis;
 253→}
 254→.search-suggestion-meta{
 255→    font-family: var(--font-ui);
 256→    font-size: 0.68rem;
 257→    font-weight: 450;
 258→    color: var(--text-faint);
 259→    letter-spacing: 0.01rem;
 260→}
 261→.search-suggestion-muted{
 262→    color: var(--text-faint);
 263→    cursor: default;
 264→    border-left-color: transparent !important;
 265→}
 266→.postcards-parent-container{
 267→    position: relative;
 268→    display: flex;
 269→    flex-direction: column;
 270→    align-items: center;
 271→    width: 100%;
 272→    margin-bottom: 1rem;
 273→    gap: 16px;
 274→    padding: 0 16px;
 275→    box-sizing: border-box;
 276→}
 277→.postcards-parent-loading-container{
 278→    position: relative;
 279→    top: 90px;
 280→    display: flex;
 281→    justify-content: center;
 282→    align-items: center;
 283→    flex-direction: column;
 284→    width: 100%;
 285→    height: 100vh;
 286→}
 287→.loading-newsfeed-bg{
 288→    display: flex;
 289→    justify-content: center;
 290→    align-items: center;
 291→    width: 100%;
 292→    height: 100%;
 293→}
 294→.jounral-view-image{
 295→    width: 400px;
 296→    height: auto;
 297→}
 298→.inview{
 299→    display: flex;
 300→    justify-content: center;
 301→    align-items: center;
 302→    width: 100%;
 303→    min-height: 35px;
 304→}
 305→
 306→/* ── Card ── */
 307→.cards{
 308→    position: relative;
 309→    display: flex;
 310→    flex-direction: column;
 311→    justify-content: flex-start;
 312→    align-items: center;
 313→    width: 99%;
 314→    max-width: 100%;
 315→    min-height: fit-content;
 316→    background-color: var(--bg-card);
 317→    border: 1px solid var(--border-card);
 318→    border-radius: 12px;
 319→    overflow: hidden;
 320→    cursor: pointer;
 321→    transition: box-shadow 0.25s ease, transform 0.25s ease;
 322→}
 323→.cards:hover{
 324→    box-shadow: 0 6px 24px rgba(80, 60, 40, 0.07);
 325→    transform: translateY(-2px);
 326→}
 327→
 328→.bookmarked-content-message-container{
 329→    position: absolute;
 330→    top: 100px;
 331→    background-color: rgb(72, 208, 135);
 332→    color: rgb(255, 255, 255);
 333→    font-size: 0.78rem;
 334→    font-weight: 600;
 335→    padding: 0.45rem 1rem;
 336→    border-radius: 8px;
 337→    width: fit-content;
 338→    z-index: 11;
 339→    transition: ease-in-out 0.2s;
 340→}
 341→
 342→/* ── Banner image ── */
 343→.card-image-banner{
 344→    width: 100%;
 345→    max-height: 220px;
 346→    object-fit: cover;
 347→    display: block;
 348→    border-bottom: 1px solid var(--border-card);
 349→    transition: opacity 0.2s ease;
 350→}
 351→.cards:hover .card-image-banner{
 352→    opacity: 0.95;
 353→}
 354→
 355→/* ── Card content area ── */
 356→.card-content{
 357→    display: flex;
 358→    flex-direction: column;
 359→    gap: 0.8rem;
 360→    width: 100%;
 361→    padding: 1rem 1.15rem 0.6rem 1.15rem;
 362→    box-sizing: border-box;
 363→}
 364→
 365→/* ── User info row ── */
 366→.user-info{
 367→    display: flex;
 368→    justify-content: space-between;
 369→    align-items: center;
 370→}
 371→.user-info-child-container{
 372→    display: flex;
 373→    align-items: center;
 374→    height: 100%;
 375→    gap: 0.4rem;
 376→    width: fit-content;
 377→}
 378→.user-avatar-container{
 379→    display: flex;
 380→    align-items: center;
 381→    justify-content: center;
 382→    width: fit-content;
 383→    height: fit-content;
 384→    cursor: pointer;
 385→}
 386→.user-info-avatar{
 387→    width: 22px;
 388→    height: 22px;
 389→    border-radius: 50%;
 390→    object-fit: cover;
 391→}
 392→.user-avatar-container.avatar-ring-legend{
 393→    border-radius: 50%;
 394→    border: 2px solid #FFD700;
 395→    box-shadow:
 396→        0 0 6px 1px rgba(255, 215, 0, 0.5),
 397→        0 0 12px 2px rgba(255, 215, 0, 0.35),
 398→        0 0 20px 4px rgba(255, 215, 0, 0.2);
 399→    animation: glow-legend 2s ease-in-out infinite alternate;
 400→}
 401→.user-avatar-container.avatar-ring-og{
 402→    border-radius: 50%;
 403→    border: 2px solid #9B59FF;
 404→    box-shadow:
 405→        0 0 6px 1px rgba(155, 89, 255, 0.5),
 406→        0 0 12px 2px rgba(155, 89, 255, 0.35),
 407→        0 0 20px 4px rgba(155, 89, 255, 0.2);
 408→    animation: glow-og 2s ease-in-out infinite alternate;
 409→}
 410→
 411→@keyframes glow-legend {
 412→    from {
 413→        box-shadow:
 414→            0 0 6px 1px rgba(255, 215, 0, 0.5),
 415→            0 0 12px 2px rgba(255, 215, 0, 0.35),
 416→            0 0 20px 4px rgba(255, 215, 0, 0.2);
 417→    }
 418→    to {
 419→        box-shadow:
 420→            0 0 8px 2px rgba(255, 215, 0, 0.6),
 421→            0 0 16px 4px rgba(255, 215, 0, 0.4),
 422→            0 0 24px 6px rgba(255, 215, 0, 0.25);
 423→    }
 424→}
 425→
 426→@keyframes glow-og {
 427→    from {
 428→        box-shadow:
 429→            0 0 6px 1px rgba(155, 89, 255, 0.5),
 430→            0 0 12px 2px rgba(155, 89, 255, 0.35),
 431→            0 0 20px 4px rgba(155, 89, 255, 0.2);
 432→    }
 433→    to {
 434→        box-shadow:
 435→            0 0 8px 2px rgba(155, 89, 255, 0.6),
 436→            0 0 16px 4px rgba(155, 89, 255, 0.4),
 437→            0 0 24px 6px rgba(155, 89, 255, 0.25);
 438→    }
 439→}
 440→.user-name-container{
 441→    display: flex;
 442→    align-items: center;
 443→    gap: 0.2rem;
 444→}
 445→.user-newsfeed-name{
 446→    font-family: var(--font-ui);
 447→    font-size: 0.78rem;
 448→    font-weight: 600;
 449→    letter-spacing: 0.005rem;
 450→    margin: 0;
 451→    padding: 0;
 452→    cursor: pointer;
 453→    color: var(--text-secondary);
 454→    transition: color 0.15s ease;
 455→}
 456→.user-newsfeed-name:hover{
 457→    text-decoration: underline;
 458→    color: var(--accent-sage);
 459→}
 460→.name-info-separator{
 461→    display: flex;
 462→    justify-content: center;
 463→    align-items: center;
 464→    width: fit-content;
 465→    height: fit-content;
 466→    color: var(--text-separator);
 467→    font-size: 0.4rem;
 468→    user-select: none;
 469→}
 470→.user-info-email-container{
 471→    display: none;
 472→}
 473→.user-info-email{
 474→    padding: 0;
 475→    margin: 0;
 476→    font-family: var(--font-ui);
 477→    font-size: 0.75rem;
 478→    font-weight: 400;
 479→    color: var(--text-faint);
 480→}
 481→.user-post-date-container{
 482→    display: flex;
 483→    justify-content: center;
 484→    align-items: center;
 485→    width: fit-content;
 486→    height: fit-content;
 487→    cursor: default;
 488→    user-select: none;
 489→}
 490→.user-post-privacy{
 491→    display: flex;
 492→    justify-content: center;
 493→    align-items: center;
 494→    width: fit-content;
 495→    height: fit-content;
 496→    cursor: default;
 497→    user-select: none;
 498→    color: var(--text-heading);
 499→}
 500→.user-post-date{
 501→    padding: 0;
 502→    margin: 0;
 503→    font-family: var(--font-ui);
 504→    font-size: 0.75rem;
 505→    font-weight: 400;
 506→    color: var(--text-faint);
 507→}
 508→.user-post-settings{
 509→    position: relative;
 510→    display: flex;
 511→    flex-direction: column;
 512→    justify-self: flex-end;
 513→    width: fit-content;
 514→    height: fit-content;
 515→    cursor: pointer;
 516→    user-select: none;
 517→    color: var(--text-heading);
 518→}
 519→.setting-modal{
 520→    display: flex;
 521→    justify-content: center;
 522→    align-items: center;
 523→    position: absolute;
 524→    right: 25px;
 525→    bottom: 10px;
 526→    width: 200px;
 527→    height: 100px;
 528→    border-radius: 10px;
 529→    z-index: 200;
 530→    background-color: var(--bg-elevated);
 531→    box-shadow: 0 8px 30px rgba(0, 0, 0, 0.12);
 532→    border: 1px solid var(--border-card);
 533→}
 534→
 535→/* ── Content (title + text) ── */
 536→.content-container{
 537→    display: flex;
 538→    flex-direction: column;
 539→    justify-content: flex-start;
 540→    align-items: flex-start;
 541→    user-select: none;
 542→    gap: 0.5rem;
 543→}
 544→.feed-text-content-container{
 545→    display: flex;
 546→    flex-direction: column;
 547→    width: 100%;
 548→    height: 100%;
 549→    justify-content: flex-start;
 550→    align-items: flex-start;
 551→    gap: 0.35rem;
 552→}
 553→.feed-title-content{
 554→    display: flex;
 555→    justify-content: center;
 556→    align-items: center;
 557→}
 558→.cards.is-canvas-card .feed-title-content{
 559→    flex-direction: row;
 560→    justify-content: flex-start;
 561→    gap: 0.45rem;
 562→}
 563→.feed-title{
 564→    margin: 0;
 565→    padding: 0;
 566→    font-family: "Lexend Deca", sans-serif;
 567→    font-size: 1.1rem;
 568→    font-weight: 700;
 569→    line-height: 1.45;
 570→    letter-spacing: -0.025rem;
 571→    color: var(--text-heading);
 572→}
 573→.feed-text-content{
 574→    padding: 0;
 575→    margin: 0;
 576→    font-family: var(--font-serif);
 577→    font-weight: 400;
 578→    color: var(--text-body);
 579→    line-height: 1.7;
 580→    font-size: 0.88rem;
 581→    letter-spacing: 0.005rem;
 582→}
 583→
 584→.canvas-card-actions{
 585→    display: flex;
 586→    flex-wrap: wrap;
 587→    gap: 0.42rem;
 588→    width: 100%;
 589→    margin-top: -0.1rem;
 590→}
 591→
 592→.canvas-card-action-btn{
 593→    border: 1px solid var(--border-card);
 594→    background: var(--bg-secondary);
 595→    color: var(--text-secondary);
 596→    border-radius: 999px;
 597→    padding: 0.3rem 0.65rem;
 598→    font-size: 0.68rem;
 599→    font-weight: 620;
 600→    cursor: pointer;
 601→    transition: border-color 0.2s ease, background 0.2s ease, color 0.2s ease;
 602→}
 603→
 604→.canvas-card-action-btn:hover{
 605→    border-color: var(--accent-sage);
 606→    color: var(--accent-sage);
 607→}
 608→
 609→.canvas-card-action-btn.is-remix{
 610→    border-color: color-mix(in srgb, var(--accent-purple) 42%, var(--border-card));
 611→    color: var(--accent-purple);
 612→}
 613→
 614→/* ── Icon bar ── */
 615→.card-icons-container{
 616→    display: flex;
 617→    flex-wrap: wrap;
 618→    width: 100%;
 619→    padding: 0.5rem 1.15rem 0.85rem 1.15rem;
 620→    min-height: 22px;
 621→    align-items: center;
 622→    justify-content: flex-start;
 623→    gap: 0.5rem;
 624→    box-sizing: border-box;
 625→    border-top: 1px solid var(--border-card);
 626→}
 627→#card-icons{
 628→    display: flex;
 629→    justify-content: center;
 630→    align-items: center;
 631→    padding: 0.35rem;
 632→    border-radius: 50%;
 633→    transition: background-color 0.2s ease;
 634→    gap: 0.3rem;
 635→}
 636→#card-icons-view{
 637→    display: flex;
 638→    justify-content: center;
 639→    align-items: center;
 640→    padding: 0.1rem;
 641→    border-radius: 50%;
 642→    transition: background-color 0.2s ease;
 643→    gap: 0.3rem;
 644→}
 645→.card-icons{
 646→    display: flex;
 647→    width: fit-content;
 648→    height: fit-content;
 649→    justify-content: center;
 650→    align-items: center;
 651→}
 652→.icon-container{
 653→    display: flex;
 654→    justify-content: center;
 655→    align-items: center;
 656→}
 657→.icon-container p{
 658→    font-family: var(--font-ui);
 659→}
 660→
 661→.like-button:hover .svg-like path{
 662→    fill: rgb(255, 116, 116);
 663→}
 664→.like-button:hover{
 665→    background-color: rgba(255, 161, 161, 0.12);
 666→}
 667→.comment-button:hover{
 668→    background-color: rgba(212, 168, 83, 0.12);
 669→}
 670→.comment-button:hover .svg-comment path{
 671→    fill: var(--accent-amber);
 672→}
 673→.bookmark-button:hover{
 674→    background-color: rgba(245, 158, 11, 0.12);
