      '--vibe-border': 'rgba(123, 104, 174, 0.45)',
      '--vibe-badge-bg': 'rgba(123, 104, 174, 0.18)',
      '--vibe-badge-text': '#7B68AE',
      '--vibe-glow': 'rgba(123, 104, 174, 0.15)',
